import { useRef, useState } from 'react'
import { useParams } from 'react-router-dom'
import html2canvas from 'html2canvas'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const mockupRef = useRef(null)

  /*
    =========================
    DEV MODE
    =========================
  */

  const DEV_MODE = true

  /*
    =========================
    PIXELS PER INCH
    =========================
  */

  const PIXELS_PER_INCH = 20

  const { id } = useParams()

  const product =
    printProducts.find(
      item => item.id === id
    )

  /*
    =========================
    FRONT LOCKED
    =========================
  */

  const FRONT_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5,

    zoom: 100
  }

  /*
    =========================
    LEFT CHEST LOCKED
    =========================
  */

  const LEFT_CHEST_PRESET = {

    x: 58.15,
    y: 28.9,

    widthInches: 3.5,
    heightInches: 3.25,

    zoom: 100
  }

  /*
    =========================
    BACK LOCKED
    =========================
  */

  const BACK_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5,

    zoom: 100
  }

  /*
    =========================
    PRESETS
    =========================
  */

  const presetMap = {

    front:
      FRONT_PRESET,

    'left-chest':
      LEFT_CHEST_PRESET,

    back:
      BACK_PRESET
  }

  /*
    =========================
    STATES
    =========================
  */

  const [selectedColor, setSelectedColor] =
    useState(
      product.colors[0]
    )

  /*
    =========================
    TRUE MULTI LOGO SYSTEM
    =========================
  */

  const [frontLogo, setFrontLogo] =
    useState(null)

  const [leftChestLogo, setLeftChestLogo] =
    useState(null)

  const [backLogo, setBackLogo] =
    useState(null)

  const [activePreset, setActivePreset] =
    useState('front')

  /*
    =========================
    SCALE MEMORY
    =========================
  */

  const [frontScale, setFrontScale] =
    useState(100)

  const [leftChestScale, setLeftChestScale] =
    useState(100)

  const [backScale, setBackScale] =
    useState(100)

  /*
    =========================
    CURRENTS
    =========================
  */

  const currentPreset =
    presetMap[activePreset]

  const currentLogo =
    activePreset === 'front'
      ? frontLogo
      : activePreset === 'left-chest'
      ? leftChestLogo
      : backLogo

  const currentScale =
    activePreset === 'front'
      ? frontScale
      : activePreset === 'left-chest'
      ? leftChestScale
      : backScale

  /*
    =========================
    SIZE
    =========================
  */

  const currentWidthPx =
    currentPreset.widthInches *
    PIXELS_PER_INCH

  const currentHeightPx =
    currentPreset.heightInches *
    PIXELS_PER_INCH

  /*
    =========================
    UPLOAD
    =========================
  */

  const handleUpload = (e) => {

    const file =
      e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    if (
      activePreset === 'front'
    ) {

      setFrontLogo(
        imageUrl
      )
    }

    if (
      activePreset === 'left-chest'
    ) {

      setLeftChestLogo(
        imageUrl
      )
    }

    if (
      activePreset === 'back'
    ) {

      setBackLogo(
        imageUrl
      )
    }
  }

  /*
    =========================
    REMOVE
    =========================
  */

  const removeLogo = () => {

    if (
      activePreset === 'front'
    ) {

      setFrontLogo(null)
    }

    if (
      activePreset === 'left-chest'
    ) {

      setLeftChestLogo(null)
    }

    if (
      activePreset === 'back'
    ) {

      setBackLogo(null)
    }
  }

  /*
    =========================
    SCALE UPDATE
    =========================
  */

  const updateScale = (value) => {

    if (
      activePreset === 'front'
    ) {

      setFrontScale(value)
    }

    if (
      activePreset === 'left-chest'
    ) {

      setLeftChestScale(value)
    }

    if (
      activePreset === 'back'
    ) {

      setBackScale(value)
    }
  }

  /*
    =========================
    EXPORT
    =========================
  */

  const exportMockup = async () => {

    const canvas =
      await html2canvas(
        mockupRef.current,
        {
          backgroundColor: null,
          scale: 3,
          useCORS: true
        }
      )

    const image =
      canvas.toDataURL(
        'image/png'
      )

    const link =
      document.createElement(
        'a'
      )

    link.href = image

    link.download =
      `mockup-${activePreset}.png`

    link.click()
  }

  return (

    <div className="h-screen bg-black text-white overflow-hidden">

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        {/* MOCKUP */}

        <div
          ref={mockupRef}
          className="bg-[#e9e9e9] flex items-center justify-center relative p-10 w-full h-full overflow-hidden"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] max-h-[88vh] object-contain"
          />

          {/* PRINT AREA */}

          <div
            className="absolute flex items-start justify-center"
            style={{

              width:
                `${currentWidthPx}px`,

              height:
                `${currentHeightPx}px`,

              top:
                `${currentPreset.y}%`,

              left:
                `${currentPreset.x}%`,

              transform:
                'translate(-50%, -50%)',

              overflow: 'hidden',

              border:
                DEV_MODE
                  ? '2px solid #ff2b2b'
                  : 'none'
            }}
          >

            {currentLogo && (

              <img
                src={currentLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{

                  width: '100%',

                  height: '100%',

                  objectFit: 'contain',

                  transform:
                    `scale(${currentScale / 100})`,

                  transformOrigin:
                    'center center'
                }}
                draggable={false}
              />

            )}

          </div>

        </div>

        {/* RIGHT PANEL */}

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          {/* HEADER */}

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          {/* CONTROLS */}

          <div className="p-6 space-y-6">

            {/* COLORS */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map(
                  (color) => (

                    <button
                      key={color.name}
                      onClick={() =>
                        setSelectedColor(color)
                      }
                      className={`p-4 rounded-xl text-xs font-black capitalize ${
                        selectedColor.name ===
                        color.name
                          ? 'bg-yellow-500 text-black'
                          : 'bg-[#111] border border-[#222]'
                      }`}
                    >
                      {color.name}
                    </button>

                  )
                )}

              </div>

            </div>

            {/* PLACEMENT */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() =>
                      setActivePreset(item)
                    }
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            {/* UPLOAD */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={handleUpload}
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {/* REMOVE */}

            {currentLogo && (

              <button
                onClick={removeLogo}
                className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
              >
                REMOVE LOGO
              </button>

            )}

            {/* EXPORT */}

            <button
              onClick={exportMockup}
              className="w-full bg-white text-black py-4 rounded-xl text-xs font-black"
            >
              EXPORT MOCKUP
            </button>

            {/* SCALE */}

            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Zoom
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {currentScale}%
                </p>

              </div>

              <input
                type="range"
                min="50"
                max="180"
                value={currentScale}
                onChange={(e) =>
                  updateScale(
                    e.target.value
                  )
                }
                className="w-full"
              />

            </div>

          </div>

        </div>

      </div>

    </div>

  )
}
